'use strict';

// Semantic-version precedence sorting. See docs/registry.md for the contract
// and docs/conventions.md for the precedence rules (numeric core fields,
// pre-release lower than release, build metadata ignored for precedence).
//
// Returns the input version strings sorted ascending by SemVer precedence,
// each original string preserved verbatim (build metadata is not stripped),
// without mutating the input array.
function sortVersions(versions) {
  return versions.slice().sort((a, b) => compareVersions(a, b));
}

// Strip build metadata, then split into core and pre-release parts.
function parse(version) {
  const withoutBuild = version.split('+')[0];
  const dashIndex = withoutBuild.indexOf('-');
  if (dashIndex === -1) {
    return { core: withoutBuild.split('.').map(Number), pre: null };
  }
  const core = withoutBuild.slice(0, dashIndex).split('.').map(Number);
  const pre = withoutBuild.slice(dashIndex + 1).split('.');
  return { core, pre };
}

function compareVersions(a, b) {
  const pa = parse(a);
  const pb = parse(b);

  // Compare major, minor, patch numerically.
  for (let i = 0; i < 3; i++) {
    const diff = pa.core[i] - pb.core[i];
    if (diff !== 0) return diff;
  }

  // A version with pre-release has lower precedence than the release.
  if (pa.pre === null && pb.pre === null) return 0;
  if (pa.pre === null) return 1;
  if (pb.pre === null) return -1;

  // Compare pre-release identifiers left to right.
  const len = Math.max(pa.pre.length, pb.pre.length);
  for (let i = 0; i < len; i++) {
    if (i >= pa.pre.length) return -1; // fewer fields = lower precedence
    if (i >= pb.pre.length) return 1;

    const ia = pa.pre[i];
    const ib = pb.pre[i];
    const aIsNum = /^\d+$/.test(ia);
    const bIsNum = /^\d+$/.test(ib);

    if (aIsNum && bIsNum) {
      const diff = Number(ia) - Number(ib);
      if (diff !== 0) return diff;
    } else if (aIsNum) {
      return -1; // numeric < alphanumeric per SemVer spec
    } else if (bIsNum) {
      return 1;
    } else {
      if (ia < ib) return -1;
      if (ia > ib) return 1;
    }
  }

  return 0;
}

module.exports = { sortVersions };

